// Supabase webhook sends payload as body.record
const record = $input.first().json.body?.record ?? $input.first().json.record ?? $input.first().json;

const name    = record.name  ?? 'Kamu';
const email   = record.email;
const code    = record.code;
const siteUrl = 'https://YOUR_SITE.netlify.app'; // ← ganti dengan URL Netlify kamu

const peerLink   = `${siteUrl}/peer/${code}`;
const resultLink = `${siteUrl}/test/result`;

const htmlContent = `
<!DOCTYPE html>
<html lang="id">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; color: #1a1a2e; background: #f8f8f8; margin: 0; padding: 0; }
    .wrapper { max-width: 600px; margin: 0 auto; background: #ffffff; }
    .header { background: linear-gradient(135deg, #4f46e5 0%, #7c3aed 100%); padding: 40px 32px; text-align: center; }
    .header h1 { color: #ffffff; font-size: 26px; margin: 0; font-weight: 700; }
    .header p  { color: rgba(255,255,255,0.85); margin: 8px 0 0; font-size: 14px; }
    .body  { padding: 32px; }
    .body p { line-height: 1.7; color: #333; font-size: 15px; margin: 0 0 16px; }
    .code-box { background: #f0f0ff; border: 1px solid #c7d2fe; border-radius: 10px; padding: 16px 20px; text-align: center; margin: 24px 0; }
    .code-box .label { font-size: 11px; text-transform: uppercase; letter-spacing: 2px; color: #6366f1; font-weight: 600; }
    .code-box .code  { font-size: 32px; font-weight: 800; color: #4f46e5; letter-spacing: 6px; margin-top: 4px; }
    .btn { display: inline-block; background: #4f46e5; color: #ffffff !important; padding: 14px 28px; border-radius: 30px; text-decoration: none; font-weight: 600; font-size: 15px; margin: 8px 0; }
    .btn-green { background: #059669; }
    .link-text { color: #6366f1; font-size: 13px; word-break: break-all; }
    .divider { border: none; border-top: 1px solid #eee; margin: 28px 0; }
    .footer { background: #f0f0ff; padding: 24px 32px; text-align: center; }
    .footer p { color: #9ca3af; font-size: 12px; margin: 0; }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="header">
      <h1>🪟 Johari Window-mu sudah siap!</h1>
      <p>Kenali dirimu dari perspektif orang lain</p>
    </div>
    <div class="body">
      <p>Hai <strong>${name}</strong>,</p>
      <p>Self-assessment kamu sudah selesai! Sekarang saatnya mengundang orang-orang yang mengenalmu untuk mengisi perspektif mereka tentangmu.</p>

      <div class="code-box">
        <div class="label">Kode unik Johari Window-mu</div>
        <div class="code">${code}</div>
      </div>

      <p>Bagikan link ini ke minimal 3 orang — rekan kerja, teman, atau mentor yang sering berinteraksi denganmu:</p>

      <div style="text-align:center; margin: 24px 0">
        <a href="${peerLink}" class="btn">Bagikan ke peer →</a>
      </div>

      <p style="font-size:13px; color:#666">Atau salin link ini secara manual:</p>
      <p class="link-text">${peerLink}</p>

      <hr class="divider">

      <p>Setelah minimal 1 orang mengisi, kamu bisa langsung melihat Johari Window lengkapmu:</p>

      <div style="text-align:center; margin: 24px 0">
        <a href="${resultLink}" class="btn btn-green">Lihat hasil →</a>
      </div>

      <p style="font-size:13px; color:#888">Semakin banyak peer yang mengisi, semakin akurat dan kaya hasil Johari Window-mu. Idealnya minimal 3–5 orang.</p>
    </div>
    <div class="footer">
      <p>Email ini dikirim otomatis dari <strong>Johari Window ID</strong>.<br>Jika kamu tidak merasa membuat akun ini, abaikan saja email ini.</p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    sender: {
      name: 'Johari Window ID',
      email: 'noreply@YOUR_DOMAIN.com'  // ← ganti dengan email sender terverifikasi di Brevo
    },
    to: [{ email, name }],
    subject: `Johari Window-mu sudah siap, ${name}! 🪟`,
    htmlContent
  }
}];
